class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

    static final String TIMESTAMP_CREATED = "wsse.timestamp.created";
    static final String TIMESTAMP_EXPIRES = "wsse.timestamp.expires";
    static final String MESSAGE_ID = "wsse.message.id";

    private static final String WSSE_NS =
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS =
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final Duration ALLOWED_CLOCK_SKEW = Duration.ofMinutes(2);
    private static final Duration MAX_TTL = Duration.ofMinutes(5);

    private static final ConcurrentMap<String, Instant> REPLAY_CACHE = new ConcurrentHashMap<>();

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (Boolean.TRUE.equals(outbound)) {
            return true;
        }

        cleanupReplayCache();

        SOAPMessage message = context.getMessage();
        try {
            SOAPHeader header = message.getSOAPHeader();
            if (header == null) {
                throw securityFault("Missing SOAP header");
            }

            SOAPElement security = findChild(header, WSSE_NS, "Security");
            if (security == null) {
                throw securityFault("Missing WS-Security header");
            }

            SOAPElement timestamp = findChild(security, WSU_NS, "Timestamp");
            if (timestamp == null) {
                throw securityFault("Missing Timestamp token");
            }

            String created = getChildText(timestamp, WSU_NS, "Created");
            String expires = getChildText(timestamp, WSU_NS, "Expires");

            if (created == null || expires == null) {
                throw securityFault("Timestamp Created and Expires are required");
            }

            Instant createdInstant = parseInstant(created, "Invalid Created timestamp");
            Instant expiresInstant = parseInstant(expires, "Invalid Expires timestamp");

            validateTimestamp(createdInstant, expiresInstant);

            String replayKey = buildReplayKey(message, created, expires);
            Instant previous = REPLAY_CACHE.putIfAbsent(replayKey, expiresInstant);
            if (previous != null) {
                throw securityFault("Replay attack detected");
            }

            context.put(TIMESTAMP_CREATED, created);
            context.put(TIMESTAMP_EXPIRES, expires);
            context.put(MESSAGE_ID, replayKey);
            context.setScope(TIMESTAMP_CREATED, MessageContext.Scope.APPLICATION);
            context.setScope(TIMESTAMP_EXPIRES, MessageContext.Scope.APPLICATION);
            context.setScope(MESSAGE_ID, MessageContext.Scope.APPLICATION);

            return true;
        } catch (SOAPException e) {
            throw new ProtocolException("SOAP processing error", e);
        }
    }

    private void validateTimestamp(Instant created, Instant expires) {
        Instant now = Instant.now();

        if (expires.isBefore(created)) {
            throw securityFault("Timestamp Expires cannot be before Created");
        }

        if (Duration.between(created, expires).compareTo(MAX_TTL) > 0) {
            throw securityFault("Timestamp validity window exceeds allowed maximum");
        }

        if (created.isAfter(now.plus(ALLOWED_CLOCK_SKEW))) {
            throw securityFault("Timestamp Created is in the future");
        }

        if (expires.isBefore(now.minus(ALLOWED_CLOCK_SKEW))) {
            throw securityFault("Message has expired");
        }
    }

    private String buildReplayKey(SOAPMessage message, String created, String expires) throws SOAPException {
        SOAPBody body = message.getSOAPBody();
        StringBuilder bodyText = new StringBuilder();
        Iterator<?> bodyChildren = body.getChildElements();
        while (bodyChildren.hasNext()) {
            Object obj = bodyChildren.next();
            if (obj instanceof SOAPElement) {
                collectText((SOAPElement) obj, bodyText);
            }
        }
        return Integer.toHexString((created + "|" + expires + "|" + bodyText).hashCode());
    }

    private void collectText(SOAPElement element, StringBuilder sb) {
        Iterator<?> it = element.getChildElements();
        while (it.hasNext()) {
            Object child = it.next();
            if (child instanceof SOAPElement) {
                SOAPElement se = (SOAPElement) child;
                collectText(se, sb);
            } else if (child instanceof Node) {
                String value = ((Node) child).getValue();
                if (value != null) {
                    sb.append(value.trim()).append('|');
                }
            }
        }
    }

    private void cleanupReplayCache() {
        Instant now = Instant.now();
        for (String key : REPLAY_CACHE.keySet()) {
            Instant expiry = REPLAY_CACHE.get(key);
            if (expiry == null || expiry.isBefore(now.minus(ALLOWED_CLOCK_SKEW))) {
                REPLAY_CACHE.remove(key);
            }
        }
    }

    private SOAPElement findChild(SOAPElement parent, String ns, String local) {
        Iterator<?> it = parent.getChildElements(new QName(ns, local));
        if (it.hasNext()) {
            Object obj = it.next();
            if (obj instanceof SOAPElement) {
                return (SOAPElement) obj;
            }
        }

        Iterator<?> all = parent.getChildElements();
        while (all.hasNext()) {
            Object obj = all.next();
            if (obj instanceof SOAPElement) {
                SOAPElement el = (SOAPElement) obj;
                if (local.equals(el.getLocalName()) && ns.equals(el.getNamespaceURI())) {
                    return el;
                }
            }
        }
        return null;
    }

    private String getChildText(SOAPElement parent, String ns, String local) {
        SOAPElement child = findChild(parent, ns, local);
        return child != null ? child.getValue() : null;
    }

    private Instant parseInstant(String value, String message) {
        try {
            return Instant.parse(value);
        } catch (DateTimeParseException e) {
            try {
                return OffsetDateTime.parse(value).toInstant();
            } catch (DateTimeParseException ex) {
                throw securityFault(message);
            }
        }
    }

    private RuntimeException securityFault(String reason) {
        try {
            SOAPFactory factory = SOAPFactory.newInstance(SOAPConstants.SOAP_1_1_PROTOCOL);
            SOAPFault fault = factory.createFault();
            fault.setFaultCode(new QName(SOAPConstants.URI_NS_SOAP_ENVELOPE, "Client"));
            fault.setFaultString("WS-Security validation failed: " + reason);
            return new ProtocolException(fault.getFaultString());
        } catch (SOAPException e) {
            return new ProtocolException("WS-Security validation failed: " + reason, e);
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    @Override
    public Set<QName> getHeaders() {
        return Collections.singleton(new QName(WSSE_NS, "Security"));
    }
}

